--
-- Name: agent; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.agent (
    agent_id uuid NOT NULL,
    name character varying(100) NOT NULL,
    region character varying(100),
    provider character varying(20),
    status character varying(20) DEFAULT 'offline'::character varying NOT NULL,
    version character varying(50),
    os character varying(50),
    arch character varying(20),
    last_heartbeat timestamp with time zone,
    registered_at timestamp with time zone DEFAULT now() NOT NULL,
    api_key character varying(255) NOT NULL,
    tags jsonb,
    project_id character(14) NOT NULL,
    tester_id uuid,
    api_key_hash character varying(64)
);


--
-- Name: agent_command; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.agent_command (
    command_id uuid DEFAULT gen_random_uuid() NOT NULL,
    agent_id uuid NOT NULL,
    config_id uuid,
    verb text NOT NULL,
    args jsonb DEFAULT '{}'::jsonb NOT NULL,
    status text DEFAULT 'pending'::text NOT NULL,
    result jsonb,
    error_message text,
    created_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    started_at timestamp with time zone,
    finished_at timestamp with time zone
);


--
-- Name: alert_channel; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.alert_channel (
    channel_id uuid DEFAULT gen_random_uuid() NOT NULL,
    project_id text NOT NULL,
    kind text NOT NULL,
