    config jsonb DEFAULT '{}'::jsonb NOT NULL,
    enabled boolean DEFAULT true NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT alert_channel_kind_check CHECK ((kind = ANY (ARRAY['webhook'::text, 'email'::text])))
);


--
-- Name: alert_event; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.alert_event (
    event_id uuid DEFAULT gen_random_uuid() NOT NULL,
    rule_id uuid NOT NULL,
    run_id uuid NOT NULL,
    fired_at timestamp with time zone DEFAULT now() NOT NULL,
    state text NOT NULL,
    value double precision,
    message text,
    delivery_status text,
    CONSTRAINT alert_event_state_check CHECK ((state = ANY (ARRAY['firing'::text, 'resolved'::text])))
);


--
-- Name: alert_rule; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.alert_rule (
    rule_id uuid DEFAULT gen_random_uuid() NOT NULL,
    project_id text NOT NULL,
    test_config_id uuid,
    metric text NOT NULL,
    comparator text NOT NULL,
    threshold double precision NOT NULL,
    window_runs integer DEFAULT 1 NOT NULL,
    enabled boolean DEFAULT true NOT NULL,
    channel_id uuid NOT NULL,
    created_by uuid,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    CONSTRAINT alert_rule_comparator_check CHECK ((comparator = ANY (ARRAY['gt'::text, 'lt'::text]))),
    CONSTRAINT alert_rule_metric_check CHECK ((metric = ANY (ARRAY['p95_ms'::text, 'mean_ms'::text, 'error_rate'::text, 'success_rate'::text]))),
    CONSTRAINT alert_rule_window_runs_check CHECK (((window_runs >= 1) AND (window_runs <= 50)))
);


