-- Name: project_tester; Type: TABLE; Schema: public; Owner: -
--

CREATE TABLE public.project_tester (
    tester_id uuid DEFAULT gen_random_uuid() NOT NULL,
    project_id text NOT NULL,
    name text NOT NULL,
    cloud text NOT NULL,
    region text NOT NULL,
    vm_size text DEFAULT 'Standard_D2s_v3'::text NOT NULL,
    vm_name text,
    vm_resource_id text,
    public_ip inet,
    ssh_user text DEFAULT 'azureuser'::text NOT NULL,
    power_state text DEFAULT 'provisioning'::text NOT NULL,
    allocation text DEFAULT 'idle'::text NOT NULL,
    status_message text,
    locked_by_config_id uuid,
    installer_version text,
    last_installed_at timestamp with time zone,
    auto_shutdown_enabled boolean DEFAULT true NOT NULL,
    auto_shutdown_local_hour smallint DEFAULT 23 NOT NULL,
    next_shutdown_at timestamp with time zone,
    shutdown_deferral_count smallint DEFAULT 0 NOT NULL,
    auto_probe_enabled boolean DEFAULT false NOT NULL,
    last_used_at timestamp with time zone,
    avg_benchmark_duration_seconds integer,
    benchmark_run_count integer DEFAULT 0 NOT NULL,
    created_by uuid NOT NULL,
    created_at timestamp with time zone DEFAULT now() NOT NULL,
    updated_at timestamp with time zone DEFAULT now() NOT NULL,
    cloud_connection_id uuid,
    requested_os character varying(50) DEFAULT 'ubuntu-24.04'::character varying,
    requested_variant character varying(20) DEFAULT 'server'::character varying,
    os_distro character varying(50),
    os_version character varying(50),
    os_variant character varying(20),
    os_arch character varying(20),
    os_kernel character varying(100),
    cloud_account_id uuid,
    CONSTRAINT lock_holder_implies_locked CHECK ((((allocation = 'locked'::text) AND (locked_by_config_id IS NOT NULL)) OR ((allocation <> 'locked'::text) AND (locked_by_config_id IS NULL)))),
    CONSTRAINT lock_requires_running_vm CHECK (((allocation <> 'locked'::text) OR (power_state = 'running'::text)))
);


